var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"안토노프, 당신……?","JPN":"アントノフ、あなたって……？","ENG":"Antonov, you're...","TWN":"安東諾夫，你……？"},"stage":{"bg":"EXILER_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"그 눈, 역시 그런건가…….","JPN":"その目、やはりそういうことなのか……","ENG":"Your eye... It is like that after all...","TWN":"那隻眼睛果然還是……"},"stage":{"bg":"EXILER_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"후후, 운명이라는 건 참 짓궂군.","JPN":"ふふ、運命とは実に皮肉なものだな。","ENG":"Ha ha, fate can be so cruel.","TWN":"呵呵，真是造化弄人呢。"},"stage":{"bg":"EXILER_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"EXILER_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"이정도까지 왔으면, 아무리 둔감한 자네라도 충분히 눈치챘겠지……?","JPN":"さすがにいくら鈍感な君でも、もうわかっただろう……？","ENG":"I'm sure you've noticed by now, no matter how insensitive you are.","TWN":"事情到了這個地步，就算你再遲鈍也應該有發現吧……？"},"stage":{"bg":"EXILER_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"내가 구태여 말하지 않았던 사실에 대해서.","JPN":"私があえて言わなかった事実について。","ENG":"Regarding the truth that I have not disclosed to you.","TWN":"我當初沒有透露的真相。"},"stage":{"bg":"EXILER_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"당신은…….","JPN":"あなたは……","ENG":"You're...","TWN":"你……"},"stage":{"bg":"EXILER_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"안토노프, 당신은 <color=#ffd34c>저</color>였군요. 다른 세계의.","JPN":"アントノフ、あなたは<color=#ffd34c>私</color>だったんですね。別の世界の。","ENG":"Antonov, you're <color=#ffd34c>me</color>, from another world.","TWN":"安東諾夫，原來你就是<color=#ffd34c>我</color>。其他世界的我。"},"stage":{"bg":"EXILER_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"후후…….","JPN":"ふふ……","ENG":"Ha ha...","TWN":"呵呵……"},"stage":{"bg":"EXILER_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"그래, 나의 이름은 <color=#ffd34c>카린</color> 안토노프.","JPN":"そうだ。私の名前は<color=#ffd34c>カリン</color>アントノフ。","ENG":"Yes, my name is <color=#ffd34c>Karin</color> Antonov.","TWN":"沒錯，我的名字是<color=#ffd34c>卡琳</color>·安東諾夫。"},"stage":{"bg":"EXILER_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"우리 세계의 마지막 <color=#ffd34c>델타 세븐</color>이자.","JPN":"我が世界の最後の<color=#ffd34c>デルタセブン</color>であり。","ENG":"I am our world's last member of <color=#ffd34c>Delta Seven</color>.","TWN":"我們世界最後一位<color=#ffd34c>第七三角洲部隊</color>成員。"},"stage":{"bg":"EXILER_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"우리 세계의 마지막 <color=#ffd34c>사명</color>을 위해.","JPN":"我が世界最後の<color=#ffd34c>使命</color>のため。","ENG":"And to fulfill our world's last <color=#ffd34c>mission</color>...","TWN":"為了我們世界最後的<color=#ffd34c>使命</color>，"},"stage":{"bg":"EXILER_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"마리아 안토노프 사령관님으로부터 이름과 함선을 물려받은 대원이라네.","JPN":"マリア・アントノフ司令官から、名前と艦船を引き継いだ隊員である。","ENG":"I inherited Commander Maria Antonov's name and ship.","TWN":"從瑪麗亞·安東諾夫司令官那裡，繼承了她的姓氏和艦船。"},"stage":{"bg":"EXILER_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"……마리아 안토노프.","JPN":"……マリア・アントノフ。","ENG":"...Maria Antonov.","TWN":"……瑪麗亞·安東諾夫。"},"stage":{"bg":"EXILER_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그래서 제게 그 이름을 물어봤군요.","JPN":"だから私にその名を知っているかと聞いたんですね。","ENG":"So that's why you asked me about her name.","TWN":"所以你才問我那個名字。"},"stage":{"bg":"EXILER_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"그래, 내가 가장 존경하는 분이자, 내 부모 같은 분이셨어.","JPN":"そうだ、私が一番尊敬していた方であり、私の親のような存在だった。","ENG":"Yes. She is the person I respect the most, and she was also a parental figure to me.","TWN":"是的，我最尊敬的人，對我來說就像父母一樣。"},"stage":{"bg":"EXILER_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"그리고 이 세계의 자네 역시 존경하는 사람이 있겠지……?","JPN":"そして、この世界の君にもやはり尊敬する人物がいるだろう……？","ENG":"And I am certain you also have someone whom you respect, right...?","TWN":"這個世界的你也有尊敬的人吧……？"},"stage":{"bg":"EXILER_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"EXILER_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"나는 나의 사명을 달성하기 위해, 아주 오랜 시간 동안 차원을 항해해왔네.","JPN":"私は自分の使命を達成するために、極めて長い間次元を航海してきた。","ENG":"I have been voyaging through dimensions for ages to complete my duty.","TWN":"我為了完成我的使命，在次元中航行了很長一段時間。"},"stage":{"bg":"EXILER_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"그 사명을 이루기 위해…… 본의 아니게 자네의 세계를 무너트리려고도 했어…….","JPN":"その使命を果たすために……不本意ながら君の世界を崩壊させようともした……","ENG":"However, I unintentionally tried to destroy yours... just so I could fulfill my duty...","TWN":"為了實現那個使命……我甚至違背本意，打算摧毀你們的世界……"},"stage":{"bg":"EXILER_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"이제 와서 변명 같은 건 필요 없어요. 당신 또한 우리 세계의 해악입니다.","JPN":"今更言い訳など聞きたくありません。あなたはやはり私たちの世界の害悪です。","ENG":"Stop with the excuses. You are still harmful to our world.","TWN":"事到如今，找再多藉口也沒有用，你也是我們世界的災禍。"},"stage":{"bg":"EXILER_04","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};